mapper.insert:
SELECT NVL(MAX(menu_idx),0)+1 FROM CMS_COMMON_MENU
INSERT INTO CMS_COMMON_MENU ( menu_idx, parent_menu_idx, menu_url, menu_name, menu_type, use_yn, view_yn, print_seq, add_date, modify_date, manage_idx, content_title_yn, link_url, group_idx, menu_full_path_name
, menu_img
, menu_top_icon
, menu_left_icon
) VALUES ( #{menu_idx} , #{parent_menu_idx}, #{menu_url}, #{menu_name}, #{menu_type}, #{use_yn}, #{view_yn}, #{print_seq}, SYSDATE, SYSDATE, #{manage_idx}, #{content_title_yn}, #{link_url},
#{menu_idx}, #{menu_name}
#{group_idx}, ( SELECT LTRIM(SYS_CONNECT_BY_PATH(menu_name,' > '),' >') || ' > ' || #{menu_name} AS menu_full_path_name FROM CMS_COMMON_MENU WHERE menu_idx = #{parent_menu_idx} CONNECT BY PRIOR menu_idx = parent_menu_idx START WITH parent_menu_idx = 0 )
, #{menu_img}
, #{menu_top_icon}
, #{menu_left_icon}
)

mapper.select:
SELECT COUNT(*) FROM CMS_COMMON_MENU
WHERE
	parent_menu_idx = #{menu_idx}
